\displaystyle{\begin{aligned}
   {\frac{\frac{5}{r}}{30-\frac{5t}{3}}} 
      \amp = {\frac{\frac{5}{r}}{30-\frac{5t}{3}}} \cdot \frac{{3r}}{{3r}} \\
      \amp = \frac{ \frac{5}{r} \cdot 3 r}{(30-\frac{5 t}{3}) \cdot 3 r} \\
      \amp = \frac{5 \cdot 3}{30 \cdot 3 r - \frac{5 t}{3} \cdot 3 r} \\
      \amp = \frac{15}{90 r - 5 r t} \\
      \amp = \frac{15}{5 r (18 - t)} \\
      \amp = {\frac{3}{r\mathopen{}\left(18-t\right)}\hbox{ or }\frac{3}{18r-rt}}
\end{aligned}
    }
